import{_ as a,p as e,q as r,a1 as i}from"./framework-caba6eb2.js";const t={},p=i('<h1 id="课程" tabindex="-1"><a class="header-anchor" href="#课程" aria-hidden="true">#</a> 课程</h1><p>Ham拥有高度自定义化的课程表。你可以将你的学习课程导入到Ham中，Ham将会在适当的时刻提醒你上课。</p><h2 id="添加、编辑、删除课程" tabindex="-1"><a class="header-anchor" href="#添加、编辑、删除课程" aria-hidden="true">#</a> 添加、编辑、删除课程</h2><div class="custom-container tip"><p class="custom-container-title">在执行编辑或删除操作前，请了解下面词语的含义</p><ul><li><p><strong>这节课</strong></p><p>一周内有连续时间段的<strong>单一</strong>课程</p></li><li><p><strong>同一门同时间段的课</strong></p><p>相同时间段、相同课头号的所有课程</p></li><li><p><strong>这门课</strong></p><p>课头号相同的所有课程</p></li></ul><blockquote><p><strong>举例</strong></p><p>张三有高等数学（周二 2-4节，周四6-8节，1-17周）一课程，那么：</p><p>某一周 周二2-4节 -&gt; 一节课</p><p>1-17周 周二2-4节 -&gt; 同一门同时间段的课</p><p>1-17周 周二2-4节，周四6-8节 -&gt; 一门课</p></blockquote></div><p>课程页面中，包含着四种操作：</p><h3 id="点击" tabindex="-1"><a class="header-anchor" href="#点击" aria-hidden="true">#</a> 点击</h3><p>单击某节存在的课，可以查看该门课的详情信息。</p><p>如果该门课从教务系统导入，还可以看到这门课的课程性质、学分。</p><p>如果这门课已在Ham中录入，你可以在此查看该门课的给分情况。</p><p>你可以在课程详情中添加日程，记录你的笔记或作业，新建的日程将关联该课程；或在此处查看所有与该课程相关的日程。</p><h3 id="长按" tabindex="-1"><a class="header-anchor" href="#长按" aria-hidden="true">#</a> 长按</h3><p>长按课程表空白处，可以添加或粘贴某一节课。</p><p>长按课程，可以对该课程进行操作：</p><ul><li><p><strong>编辑</strong></p><p>更改同一门同时间段所有课程的基本信息</p></li><li><p><strong>复制、剪切</strong></p><p>仅复制、剪切这一节课</p></li><li><p><strong>删除</strong></p><p>根据你的选择删除课程</p></li></ul><h3 id="拖动" tabindex="-1"><a class="header-anchor" href="#拖动" aria-hidden="true">#</a> 拖动</h3><p>拖动课程，可以便捷地改变某一节课的时间。</p><h2 id="设置课程表" tabindex="-1"><a class="header-anchor" href="#设置课程表" aria-hidden="true">#</a> 设置课程表</h2><p>可以在设置课程表页面中设置开学日期、背景图片，或导入课程表。</p><div class="custom-container tip"><p class="custom-container-title">提醒</p><p>必须设置开学日期，Ham才能知道你想使用的是哪个学期的课程表，才能准确地提醒你上课。</p></div><p>也可以在设置中添加课程表的背景图片、更改课程的透明度与毛玻璃透明度。</p><p>也可以导入武汉大学本科生与研究生课程表。</p><h2 id="小组件" tabindex="-1"><a class="header-anchor" href="#小组件" aria-hidden="true">#</a> 小组件</h2><p>Ham拥有课程小组件。你可以把小组件放在桌面上，快捷了解今日或明日课程。</p><h2 id="必要的权限" tabindex="-1"><a class="header-anchor" href="#必要的权限" aria-hidden="true">#</a> 必要的权限</h2><h3 id="课程提醒" tabindex="-1"><a class="header-anchor" href="#课程提醒" aria-hidden="true">#</a> 课程提醒</h3><ul><li>Android: 自启动、通知权限</li><li>iOS: 通知</li></ul><h3 id="小组件-1" tabindex="-1"><a class="header-anchor" href="#小组件-1" aria-hidden="true">#</a> 小组件</h3><ul><li>Android: 自启动</li></ul>',28),n=[p];function d(h,s){return e(),r("div",null,n)}const l=a(t,[["render",d],["__file","course.html.vue"]]);export{l as default};
